ATE TEMP TABLE late_checkout_resolution ON COMMIT DROP AS WITH order_matches AS ( SELECT source.source_row, source.confirmation_code, source.amount, count(orders.id)::integer AS order_match_count, min(orders.id) AS order_id, min(orders.property_id) AS property_id, min(orders.checkout) AS checkout FROM late_checkout_source source LEFT JOIN orders ON upper(trim(orders.confirmation_code)) = source.confirmation_code GROUP BY source.source_row, source.confirmation_code, source.amount ), flags AS ( SELECT matches.*, CASE WHEN matches.order_match_count = 1 THEN EXISTS ( SELECT 1 FROM finance_transactions tx WHERE tx.kind = 'income' AND lower(coalesce(tx.category, '')) = 'late_checkout' AND tx.ref_type = 'order' AND tx.ref_id = matches.order_id ) ELSE false END AS has_finance_transaction, CASE WHEN matches.order_match_count = 1 THEN EXISTS ( SELECT 1 FROM company_incomes income WHERE lower(coalesce(income.category, '')) = 'late_checkout' AND income.ref_type = 'order' AND income.ref_id = matches.order_id ) ELSE false END AS has_company_income FROM order_matches matches ) SELECT flags.*, CASE WHEN order_match_count = 0 THEN 'missing_order' WHEN order_match_count > 1 THEN 'ambiguous_order' WHEN checkout IS NULL THEN 'missing_checkout' WHEN has_finance_transaction THEN 'existing_finance_transaction' WHEN has_company_income THEN 'existing_company_income' ELSE 'ready' END AS resolution FROM flags; SELECT resolution, count(*) AS record_count, round(sum(amount), 2) AS amount_total FROM late_checkout_resolution GROUP BY resolution ORDER BY resolution; SELECT source_row, confirmation_code, amount, order_match_count, order_id, checkout, resolution FROM late_checkout_resolution WHERE resolution <> 'ready' ORDER BY source_row; SELECT count(*) AS ready_count, round(sum(amount), 2) AS ready_amount FROM late_checkout_resolution WHERE resolution = 'ready'; ROLLBACK;
